module RefModule(npc, wpcir, clock, resetn, pc);input   [31:0]  npc;
    input           clock, resetn, wpcir;

    output  [31:0]  pc;

    reg     [31:0]  unused_pcreg;

    assign pc = unused_pcreg;

    always @ (posedge clock or negedge resetn) begin
		if (resetn == 0) begin
            unused_pcreg <= -4;
        end else if (wpcir == 0) begin
			unused_pcreg <= npc;
		end else begin
			unused_pcreg <= unused_pcreg;
		end
    end
endmodule
